import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, placeBid, listenPlayers, listenRecords } from '../firebase/services';
import Countdown from '../components/Countdown';
import toast from 'react-hot-toast';

const BID_INCREMENTS = [500, 1000, 1500];

export default function PlayerDashboard() {
  const { user, playerData, logout } = useAuth(); // Correctly destructure logout here
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [records, setRecords] = useState([]);
  const [selectedIncrement, setSelectedIncrement] = useState(500);
  const [bidding, setBidding] = useState(false);
  const [tab, setTab] = useState('auction');
  const [auctionLoaded, setAuctionLoaded] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(data => { setAuction(data); setAuctionLoaded(true); }),
      listenPlayers(setPlayers),
      listenRecords(setRecords),
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const myNextBid = auction ? auction.currentBid + selectedIncrement : 0;
  const isMyTurn = auction?.currentBidder !== user?.uid;
  const hasWon = playerData?.hasWon;
  const canBid = auction?.active && !auction?.closed && !hasWon && isMyTurn;
  const isCurrentLeader = auction?.currentBidder === user?.uid;

  const handleBid = async () => {
    if (!canBid) return;
    if (new Date() > new Date(auction.endsAt)) return toast.error('Auction has ended!');
    setBidding(true);
    try {
      await placeBid(user.uid, playerData.name, myNextBid);
      toast.success(`Bid of ₹${myNextBid.toLocaleString('en-IN')} placed!`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setBidding(false);
    }
  };

  const onLogout = async () => { 
    await logout(); 
    toast.success("Logged out successfully");
  };

  const wonPlayers = players.filter(p => p.hasWon);
  const pendingPlayers = players.filter(p => !p.hasWon);

  return (
    <div className="page">
      <nav className="navbar">
        <div>
          <div className="navbar-brand">🪙 BC Circle</div>
          <div className="navbar-sub">Welcome, {playerData?.name}</div>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={onLogout}>Logout</button>
      </nav>
      {/* Rest of your JSX remains the same */}
      {/* ... (Tabs and Tab Content) */}
    </div>
  );
}
